def merge_ranges(pairs):
    sorted_pairs = sorted(pairs, key=lambda x: x[0])
    merged_pairs = [sorted_pairs[0]]
    for pair in sorted_pairs[1:]:
        last_pair = merged_pairs[-1]
        if last_pair[1] >= pair[0]:
            last_pair[1] = max(last_pair[1], pair[1])
